INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有', '不愧是老牌五星，随时随地感受到专业的服务，门口就地铁，出门好吃的太多了，游泳还有饮料送！以后来广州就认花园酒店', '2024-08-04', 5, '[''前台服务'', ''交通便利性'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233j12000f010s5vE4F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000f010zgm4FA6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000f010ln4675A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大，套房，睡得很舒服，酒店环境也很赞，两点不足，一就是1千多的房价迷你吧的', '房间很大，套房，睡得很舒服，酒店环境也很赞，两点不足，一就是1千多的房价迷你吧的饮料竟然全部收费。二就是入住时那个服务员竟然不知道我的价钱含早餐，然后询问了也答错了吃早餐的地方，新来的吗？要好好培训了。', '2024-05-26', 3, '[''性价比'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236712000e6adchd1B48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000e6ape0wE46D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000e6adqucA504_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000e6acsb80153_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000e6ahc482038_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000e6alhbhD4E7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000e6apqa70CBD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000e6adfacD59F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000e6al6pbB16B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境优美，有个园林可以喂鱼，酒店有个博物馆，前台姐姐服务周到', '环境优美，有个园林可以喂鱼，酒店有个博物馆，前台姐姐服务周到', '2024-09-18', 5, '[''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230o12000fmdr7osC013_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000fmdblc2C7EA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来到酒店经理看到我们两大三小的组合，二话不说马上给换成了亲子套房，因为来的晚预订', '来到酒店经理看到我们两大三小的组合，二话不说马上给换成了亲子套房，因为来的晚预订不到晚上自助餐位置了，经理又帮我们优先预约了第二轮自助餐，整个服务流程提现了专业以及关怀，非常满意的一次体验', '2024-06-22', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235p12000ejs51mj3693_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000ejs6oa42F5B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000ejs49903553_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000ejs8ro938BB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店位置好，交通便利，酒店设施高端大气，服务热情周到，出行首选。', '花园酒店位置好，交通便利，酒店设施高端大气，服务热情周到，出行首选。', '2024-09-10', 5, '[''交通便利性'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232n12000fhjk3ncA909_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店干净卫生，住的很舒服，多住几晚体验感更好，生日酒店还送了一个小蛋糕，预定了一', '酒店干净卫生，住的很舒服，多住几晚体验感更好，生日酒店还送了一个小蛋糕，预定了一晚瀑布酒店，感觉一般般', '2024-09-09', 5, '[''整体满意度'', ''卫生状况'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235a12000fh5nyyfE6A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231312000fh55t0g9328_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000fh535p8D93D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '感谢前台Gillian的服务，花园酒店的配套设施都很好，客房很宽敞，花园式的环境', '感谢前台Gillian的服务，花园酒店的配套设施都很好，客房很宽敞，花园式的环境很漂亮，楼顶还有博物馆，虽小却也底蕴深厚', '2024-07-26', 5, '[''前台服务'', ''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234b12000ewlnwxg6B17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000ewlmb939063_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000ewlk9zjD027_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务很好，酒店大堂大气，服务人员很热情', '服务很好，酒店大堂大气，服务人员很热情', '2024-10-08', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000g1kndec67A6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境是真的好，酒店大厅^-^气派 周边还有广州酒家 超级方便 地铁出来就是酒店 ', '环境是真的好，酒店大厅^-^气派 周边还有广州酒家 超级方便 地铁出来就是酒店 对于带娃的出行 节省不少时间了 太完美了??还贴心的送了小甜品', '2024-09-10', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236d12000fhoj4fv4ED1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000fhoj24r1292_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000fhojqth0589_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，', '酒店大堂很气派，不论是办理入住还是退房都有引导，效率挺高，房间不大，是老酒店了，胜在洗澡水很冲洗的舒服，客服小李还亲自送来小甜品。出行地铁方便吃饭可选择余地比较多，就是周边那几家很红的餐厅都需要等位好久。', '2025-02-02', 4, '[''前台服务'', ''退房/入住效率'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/02302224x8z2z4ytt6503_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g224x8z303wfzF469_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q224x8z2yj3a76E66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d224x8z2zap72D88B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z224x8z31aplv9284_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '床真舒适，美美的睡了一觉！30楼的旋转自助餐厅的食物太美味??瀑布花园太壮观了！', '床真舒适，美美的睡了一觉！30楼的旋转自助餐厅的食物太美味??瀑布花园太壮观了！', '2024-08-25', 5, '[''餐饮设施'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236312000f90nsoy5FBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234l12000f90pqupC156_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000f90lizoE984_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好好', '2024-09-17', 4, '[]', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000flnuonnCB2F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000fln5rcq22FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000flnll3h961F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星，浓郁的老广州味，喜欢喜欢有年轻时候的回忆，服务特别好。真诚细致。特别感', '老牌五星，浓郁的老广州味，喜欢喜欢有年轻时候的回忆，服务特别好。真诚细致。特别感谢James。Man c.y', '2024-08-28', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000fa965nh0786_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000fa95ujbE0CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000fa950wj913B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230e12000fa970k3E6DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000fa96v1o6D29_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000fa93s5d8D95_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店整体设施都比较完善，后花园很大，4楼还有个博物馆，是老品牌五星级酒店了，入住', '酒店整体设施都比较完善，后花园很大，4楼还有个博物馆，是老品牌五星级酒店了，入住期间羊羊精品店Livia很热情，酒店的小羊超级可爱~', '2024-07-08', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236x12000epvv4698C02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000epvj5wl439B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', 'echo小姐姐很棒 ', 'echo小姐姐很棒 
卫生：很好
